mapper.select:
SELECT qna_no AS qnaNo, member_no AS memberNo, cs_cate_no AS csCateNo, title, content, answer,
       answer_member_no AS answerMemberNo, status, reg_date AS regDate, answer_date AS answerDate
FROM qna WHERE qna_no=#{qnaNo}

mapper.update:
UPDATE qna SET member_no=#{memberNo}, cs_cate_no=#{csCateNo}, title=#{title}, content=#{content}, answer=#{answer},
    answer_member_no=#{answerMemberNo}, status=#{status}, answer_date=#{answerDate}
WHERE qna_no=#{qnaNo}
